const pendingResponse = $('Fetch Pending Approvals').first().json || {};
const auditResponse = $('Fetch Reminder Audit').first().json || {};
const pendingRows = Array.isArray(pendingResponse.body) ? pendingResponse.body : [];
const auditRows = Array.isArray(auditResponse.body) ? auditResponse.body : [];

function minutes(value) {
  if (value == null || value === '') return null;
  const n = Number(value);
  return Number.isFinite(n) && n >= 0 ? n : null;
}
function isoAgeMinutes(createdAt) {
  const t = Date.parse(createdAt);
  return Number.isFinite(t) ? Math.max(0, Math.floor((Date.now() - t) / 60000)) : 0;
}
function redactTelegramError(error, token) {
  const raw = String(error && error.message ? error.message : error || 'unknown');
  const scrubbed = token ? raw.split(token).join('[token]') : raw;
  return scrubbed.length > 200 ? scrubbed.slice(0, 197) + '...' : scrubbed;
}
function priorFor(auditId) {
  return auditRows.filter((row) => row && row.payload && row.payload.source_audit_id === auditId);
}

const reminderAfter = minutes($env.APPROVAL_REMINDER_AFTER_MINUTES) ?? 30;
const escalationAfter = minutes($env.APPROVAL_ESCALATION_AFTER_MINUTES) ?? 120;
const repeatAfter = minutes($env.APPROVAL_REMINDER_REPEAT_MINUTES) ?? 60;
const token = $env.TELEGRAM_BOT_TOKEN || '';
const primaryChat = $env.TELEGRAM_CHAT_ID || '';
const escalationChat = $env.TELEGRAM_ESCALATION_CHAT_ID || primaryChat;
const fallbackSecondApprover = $env.FLOWOPS_SECOND_APPROVER || 'ops-lead';
const audit = [];

async function sendTelegram(chat, text, buttons) {
  if (!token || !chat) return { delivered: false, notice: 'telegram skipped: TELEGRAM_BOT_TOKEN/chat not set' };
  const body = { chat_id: chat, text };
  if (buttons && buttons.length) body.reply_markup = { inline_keyboard: [buttons] };
  try {
    await this.helpers.httpRequest({ method: 'POST', url: 'https://api.telegram.org/bot' + token + '/sendMessage', body, json: true, timeout: 15000 });
    return { delivered: true, notice: null };
  } catch (e) {
    return { delivered: false, notice: 'telegram failed: ' + redactTelegramError(e, token) };
  }
}

for (const row of pendingRows) {
  if (!row || !row.audit_id) continue;
  const payload = row.payload || {};
  const age = isoAgeMinutes(row.created_at);
  const seen = priorFor(row.audit_id);
  const lastReminder = seen.find((r) => r.step === 'reminder');
  const escalated = seen.some((r) => r.step === 'escalate-second-approver' && r.status === 'success');
  const lastReminderAge = lastReminder ? isoAgeMinutes(lastReminder.created_at) : Infinity;
  const secondApprover = payload.second_approver || fallbackSecondApprover;
  let action = null;
  if (age >= escalationAfter && !escalated) action = 'escalate-second-approver';
  else if (age >= reminderAfter && (!lastReminder || lastReminderAge >= repeatAfter)) action = 'reminder';
  if (!action) continue;

  const approveUrl = payload.approve_url || (payload.approval_url ? payload.approval_url + '?decision=approve' : null);
  const rejectUrl = payload.reject_url || (payload.approval_url ? payload.approval_url + '?decision=reject' : null);
  const buttons = approveUrl && rejectUrl ? [{ text: 'Approve', url: approveUrl }, { text: 'Reject', url: rejectUrl }] : [];
  const isEscalation = action === 'escalate-second-approver';
  const text = [
    isEscalation ? 'Approval SLA escalation' : 'Approval reminder',
    'Tenant: ' + (row.tenant_name || payload.tenant_name || row.tenant_id || 'n/a'),
    'Request: ' + row.service + '/' + row.step,
    payload.title ? 'Title: ' + payload.title : null,
    payload.issue_number ? 'Issue: #' + payload.issue_number : null,
    'Age: ' + age + ' minutes',
    'Primary approver: ' + (payload.approver || 'n/a'),
    isEscalation ? 'Second approver: ' + secondApprover : null,
    'Correlation: ' + row.correlation_id,
    approveUrl ? 'Approval link attached as buttons.' : 'No approval URL stored on the waiting row; use the original HITL message.'
  ].filter(Boolean).join('\n');

  const chat = isEscalation ? escalationChat : primaryChat;
  const sent = await sendTelegram.call(this, chat, text, buttons);
  audit.push({ json: {
    tenant_id: row.tenant_id,
    correlation_id: row.correlation_id,
    service: 'approvals',
    step: action,
    status: sent.delivered ? 'success' : (sent.notice && sent.notice.startsWith('telegram skipped') ? 'skipped' : 'error'),
    payload: {
      source_audit_id: row.audit_id,
      source_service: row.service,
      source_step: row.step,
      tenant_name: row.tenant_name || payload.tenant_name,
      age_minutes: age,
      reminder_after_minutes: reminderAfter,
      escalation_after_minutes: escalationAfter,
      approver: payload.approver || null,
      second_approver: secondApprover,
      telegram_delivered: sent.delivered,
      telegram_chat: isEscalation && $env.TELEGRAM_ESCALATION_CHAT_ID ? 'escalation' : 'primary',
      notice: sent.notice
    }
  } });
}

return audit;
